"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[1721],{8097:function(e,n,i){i.d(n,{QX:function(){return t},qS:function(){return s}});let t=[{slug:"icia-lancement-programme-impact",title:"L'ICIA lance le Programme Impact pour la mont\xe9e en comp\xe9tence face \xe0 l'IA",titleEn:"ICIA launches the Impact Program for AI skills development",excerpt:"Un programme de formation con\xe7u pour accompagner les citoyens, professionnels et organisations confront\xe9s aux transformations li\xe9es \xe0 l'intelligence artificielle.",excerptEn:"A training program designed to support citizens, professionals and organizations facing AI-driven transformations.",body:"L'Institut Collectif de l'IA (ICIA) annonce le lancement de son Programme Impact, un dispositif de mont\xe9e en comp\xe9tence con\xe7u pour accompagner les publics confront\xe9s aux transformations li\xe9es \xe0 l'intelligence artificielle.\n\n## Cinq modules progressifs\n\nLe Programme Impact s'articule autour de cinq modules progressifs, sans pr\xe9requis :\n\n1. **Comprendre sans subir** — poser un vocabulaire commun, distinguer les r\xe9alit\xe9s des fantasmes\n2. **Prendre en main les outils du quotidien** — r\xe9diger, rechercher, organiser avec l'IA\n3. **Exercer son jugement** — reconna\xeetre les erreurs, les biais, les informations g\xe9n\xe9r\xe9es\n4. **Comprendre ce qu'on c\xe8de** — donn\xe9es personnelles, consentement, RGPD\n5. **Participer au d\xe9bat** — IA et travail, d\xe9mocratie, souverainet\xe9\n\n## Un programme d'int\xe9r\xeat g\xe9n\xe9ral\n\nD\xe9velopp\xe9 par l'ICIA avec le concours de Mentivis comme op\xe9rateur p\xe9dagogique, le Programme Impact est destin\xe9 aux structures associatives, \xe9ducatives, culturelles et territoriales.\n\nLes formations sont propos\xe9es en pr\xe9sentiel \xe0 Marseille (Campus Cyber.IA Euromed), en distanciel et en formats hybrides.",bodyEn:"The Institut Collectif de l'IA (ICIA) announces the launch of its Impact Program, a skills development initiative designed to support those facing AI-driven transformations.\n\n## Five progressive modules\n\nThe Impact Program is structured around five progressive modules, with no prerequisites:\n\n1. **Understand without suffering** — establish a shared vocabulary, distinguish reality from fantasy\n2. **Master everyday tools** — write, research, organize with AI\n3. **Exercise judgment** — recognize errors, biases, generated information\n4. **Understand what you give up** — personal data, consent, GDPR\n5. **Participate in the debate** — AI and work, democracy, sovereignty\n\n## A public interest program\n\nDeveloped by ICIA with Mentivis as the educational operator, the Impact Program is intended for associative, educational, cultural and territorial structures.\n\nTraining sessions are offered in-person in Marseille (Campus Cyber.IA Euromed), remotely and in hybrid formats.",category:"programmes",date:"2026-05-10",image:"/images/publications/icia-lancement-programme-impact/impact.webp"},{slug:"icia-ia-integre-mentivos-le-diagnostic-ia-rencontre-le-moteur-pedagogique",title:"L'ICIA int\xe8gre MentivisOS dans ses dispositifs de mont\xe9e en comp\xe9tences IA",titleEn:"ICIA integrates MentivisOS into its AI skills development programs",excerpt:"L'ICIA a retenu MentivisOS apr\xe8s \xe9valuation de ses fondements p\xe9dagogiques, en coh\xe9rence avec les principes qui guident ses propres interventions",excerptEn:"ICIA selected MentivisOS following an evaluation of its pedagogical foundations, in alignment with the principles that guide its own work",body:"Il existe une impasse que peu d'acteurs de la formation professionnelle acceptent de nommer : on sait mesurer les \xe9carts, on sait cartographier les besoins, on sait formuler des priorit\xe9s. Et ensuite ? On oriente vers un catalogue. On prescrit du contenu g\xe9n\xe9rique. On laisse chaque apprenant se d\xe9brouiller avec une liste de modules qui ne lui a pas \xe9t\xe9 construite.\n\nCe n'est pas un probl\xe8me de contenu disponible. C'est un probl\xe8me d'architecture p\xe9dagogique. C'est pr\xe9cis\xe9ment ce que l'int\xe9gration de MentivisOS dans les dispositifs de l'ICIA vient corriger.\n\n#### **Ce que MentivisOS fait, et ce qu'il n'est pas**\n\nMentivisOS n'est pas un LMS. La distinction m\xe9rite d'\xeatre pos\xe9e sans d\xe9tour, parce que la confusion entre outil de diffusion et moteur p\xe9dagogique est source de d\xe9penses inutiles et de r\xe9sultats non mesurables. Un LMS stocke, organise, trace. Ce qu'il ne fait pas, c'est v\xe9rifier si le contenu diffus\xe9 comble r\xe9ellement l'\xe9cart de comp\xe9tences de la personne qui le re\xe7oit. On peut valider un module sans avoir progress\xe9. Le secteur de la formation le sait. Peu l'admettent publiquement.\n\nMentivisOS est construit sur une logique diff\xe9rente. L'apprenant d\xe9clare un objectif, une situation de d\xe9part, des contraintes de temps. En moins d'une minute, le syst\xe8me produit un diagnostic complet : score de couverture, risque r\xe9siduel, dur\xe9e estim\xe9e, modules identifi\xe9s, ordre d'apprentissage. Pas une liste. Une s\xe9quence raisonn\xe9e. Le programme se construit ensuite module par module, th\xe9orie, pratique, \xe9valuation, avec un assistant p\xe9dagogique embarqu\xe9 qui reste dans le p\xe9rim\xe8tre du sujet, sans d\xe9river.\n\nCe que MentivisOS produit, c'est le programme exact dont une personne donn\xe9e a besoin. Ni plus. Ni moins.\n\n#### **Pourquoi l'ICIA int\xe8gre cet outil dans ses activit\xe9s**\n\nLa mission de l'ICIA est de d\xe9velopper une intelligence artificielle collective, ancr\xe9e dans les r\xe9alit\xe9s professionnelles et accessible au plus grand nombre : entreprises, organismes publics, associations professionnelles, \xe9tablissements d'enseignement, professions lib\xe9rales. Ces publics arrivent avec des maturit\xe9s IA radicalement diff\xe9rentes, des m\xe9tiers distincts, des rythmes contraints.\n\nLes diagnostics conduits dans le cadre des activit\xe9s de l'ICIA produisent une cartographie pr\xe9cise : qui sait quoi, qui a besoin de quoi, dans quel d\xe9lai, avec quelles priorit\xe9s m\xe9tier. La question qui suivait syst\xe9matiquement cette \xe9tape \xe9tait la suivante : comment traduire ce diagnostic en mont\xe9e en comp\xe9tences r\xe9elle, adapt\xe9e \xe0 chaque profil, sans noyer les personnes dans un catalogue qui ne leur parle pas ?\n\nMentivisOS r\xe9pond directement \xe0 cette question. Il transforme un diagnostic en programme op\xe9rationnel. Il donne corps \xe0 la feuille de route. Il permet \xe0 l'ICIA de ne pas s'arr\xeater \xe0 la prescription mais d'accompagner l'ex\xe9cution avec un outil con\xe7u pour \xe7a.\n\nL'ICIA a retenu MentivisOS apr\xe8s \xe9valuation de ses fondements p\xe9dagogiques, en coh\xe9rence avec les principes qui guident ses propres interventions : partir du besoin r\xe9el, produire quelque chose de mesurable, s'adapter \xe0 ce qui existe plut\xf4t qu'imposer une couche suppl\xe9mentaire.\n\n#### **Ce que \xe7a change concr\xe8tement pour les organisations accompagn\xe9es**\n\nPour les entreprises et \xe9quipes engag\xe9es dans les programmes de l'ICIA, MentivisOS s'int\xe8gre sans infrastructure \xe0 d\xe9ployer. Trois modes d'acc\xe8s sont disponibles : un acc\xe8s direct par apprenant, op\xe9rationnel en 24 heures ; une licence organisation avec des r\xe9f\xe9rentiels m\xe9tiers personnalis\xe9s et un onboarding d\xe9di\xe9 ; ou une connexion API avec les outils existants, LMS, SIRH ou ATS.\n\nConcr\xe8tement, une organisation qui a conduit un diagnostic IA avec l'ICIA peut, dans la continuit\xe9 imm\xe9diate, d\xe9ployer des parcours individualis\xe9s pour chaque collaborateur identifi\xe9 comme prioritaire. Sans s\xe9lectionner un prestataire de formation s\xe9par\xe9. Sans attendre la prochaine session collective. Sans acqu\xe9rir un LMS suppl\xe9mentaire.\n\nPour les organismes de formation et les \xe9tablissements qui collaborent avec l'ICIA, MentivisOS offre quelque chose de plus pr\xe9cis encore : la lisibilit\xe9 des \xe9carts \xe0 la maille fine, la fin du curriculum uniforme appliqu\xe9 indistinctement, et la construction de r\xe9f\xe9rentiels op\xe9rationnels en quelques jours.\n\n#### **Pour aller plus loin**\n\nMentivisOS est disponible d\xe8s maintenant pour les organisations accompagn\xe9es par l'ICIA. Il n'y a pas de d\xe9monstration standard. Chaque pr\xe9sentation est construite autour d'un cas r\xe9el issu de l'organisation concern\xe9e, trait\xe9 en direct.\n\nPour les organisations d\xe9j\xe0 engag\xe9es dans un programme ICIA, la question de l'int\xe9gration de MentivisOS peut \xeatre pos\xe9e directement lors du prochain point de suivi.\n\nPour celles qui d\xe9couvrent l'ICIA par ce biais : le point d'entr\xe9e reste le m\xeame. Un diagnostic, une feuille de route. Maintenant, un moteur pour l'ex\xe9cuter.",bodyEn:"There is a dead end that few actors in professional training are willing to name: we know how to measure gaps, map needs, and set priorities. And then what? We point people toward a catalog. We prescribe generic content. We leave each learner to navigate a list of modules that was never built for them.\n\nThis is not a problem of available content. It is a problem of pedagogical architecture. That is precisely what the integration of MentivisOS into ICIA's programs is designed to correct.\n\n**What MentivisOS does, and what it is not**\n\nMentivisOS is not an LMS. The distinction is worth stating plainly, because confusing a content delivery tool with a pedagogical engine produces wasted spending and unmeasurable outcomes. An LMS stores, organizes, and tracks. What it does not do is verify whether the content it delivers actually closes the skills gap of the person receiving it. You can complete a module without having moved an inch. The training industry knows this. Few say it out loud.\n\nMentivisOS is built on a different logic. The learner declares an objective, a starting situation, and time constraints. In under a minute, the system produces a complete diagnostic: coverage score, residual risk, estimated duration, identified modules, and learning sequence. Not a list. A reasoned sequence. The program then builds module by module, theory, practice, assessment, with an embedded pedagogical assistant that stays within the subject perimeter without drifting.\n\nWhat MentivisOS produces is the exact program a given person needs. No more. No less.\n\n**Why ICIA integrates this tool into its activities**\n\nICIA's mission is to develop collective artificial intelligence that is grounded in professional realities and accessible to the widest possible range of organizations: companies, public bodies, professional associations, educational institutions, and independent practitioners. These audiences arrive with radically different levels of AI maturity, distinct professional contexts, and constrained schedules.\n\nThe diagnostics conducted through ICIA's programs produce a precise map: who knows what, who needs what, within what timeframe, and against which professional priorities. The question that followed systematically from that stage was this: how do you translate a diagnostic into real skills development, adapted to each individual profile, without drowning people in a catalog that was never written for them?\n\nMentivisOS answers that question directly. It turns a diagnostic into an operational program. It gives substance to the roadmap. It allows ICIA to move beyond prescription and accompany execution with a tool purpose-built for that task.\n\nICIA selected MentivisOS following an evaluation of its pedagogical foundations, in alignment with the principles that guide its own work: starting from real need, producing something measurable, and adapting to what already exists rather than adding another layer.\n\n**What this means concretely for the organizations ICIA works with**\n\nFor companies and teams engaged in ICIA programs, MentivisOS integrates without any infrastructure to deploy. Three access modes are available: direct learner access, operational within 24 hours; an organizational license with customized professional frameworks and dedicated onboarding; or an API connection with existing tools, whether LMS, HRIS, or ATS.\n\nIn practice, an organization that has conducted an AI diagnostic with ICIA can, in immediate continuity, deploy individualized learning paths for each collaborator identified as a priority. Without selecting a separate training provider. Without waiting for the next group session. Without acquiring an additional LMS.\n\nFor training organizations and institutions that work with ICIA, MentivisOS offers something more precise still: visibility into skills gaps at a fine-grained level, an end to the uniform curriculum applied indiscriminately, and the construction of operational competency frameworks within a matter of days.\n\n**To go further**\n\nMentivisOS is available now for organizations working with ICIA. There is no standard demonstration. Every presentation is built around a real case drawn from the organization in question, processed live.\n\nFor organizations already engaged in an ICIA program, the question of integrating MentivisOS into the existing setup can be raised directly at the next review point.\n\nFor those discovering ICIA through this article: the entry point remains the same. A diagnostic, a roadmap. Now, an engine to execute it.",category:"presse",date:"2026-05-07",image:"/images/publications/icia-ia-integre-mentivos-le-diagnostic-ia-rencontre-le-moteur-pedagogique/mentivos.avif"},{slug:"icia-marius-ia-deux-projets-meme-conviction",title:"L'ICIA et Marius IA : deux projets, une m\xeame conviction",titleEn:"ICIA and Marius IA: two projects, one conviction",excerpt:"L'ICIA n'intervient pas seul dans cet \xe9cosyst\xe8me. Marius IA, bas\xe9 au Campus Cyber.IA Euromed de Marseille, partage la m\xeame conviction fondatrice",excerptEn:"ICIA does not operate alone in this ecosystem. Marius IA, based at the Campus Cyber.IA Euromed in Marseille, shares the same founding conviction",body:"Il existe un paradoxe bien r\xe9el dans le monde professionnel d'aujourd'hui : tout le monde parle d'intelligence artificielle, mais peu de gens savent vraiment quoi en faire. Entre les promesses d\xe9mesur\xe9es des vendeurs de solutions et la complexit\xe9 r\xe9glementaire qui s'installe avec l'AI Act europ\xe9en, les organisations comme les individus se retrouvent souvent seuls face \xe0 des d\xe9cisions qu'ils ne se sentent pas \xe9quip\xe9s pour prendre.\n\nCe paradoxe, c'est celui que l'ICIA a choisi de prendre en charge.\n\n**L'ICIA : l'IA comme bien commun**\n\nL'Institut Collectif de l'Intelligence Artificielle est une association \xe0 caract\xe8re d'utilit\xe9 publique. Sa mission est simple \xe0 formuler, moins simple \xe0 tenir : faire en sorte que l'intelligence artificielle ne reste pas entre les mains de quelques-uns.\n\nLa fracture se creuse vite. Ceux qui ma\xeetrisent les outils avancent. Ceux qui ne les comprennent pas subissent. Et le d\xe9bat public, souvent domin\xe9 par un discours \xe9litiste ou anxiog\xe8ne, ne leur est d'aucune aide.\n\nFace \xe0 \xe7a, l'ICIA propose des ateliers concrets et accessibles, sans pr\xe9requis techniques. Comprendre ce qu'est r\xe9ellement l'intelligence artificielle. Reconna\xeetre les deepfakes et les arnaques. Lire ce qui se passe sur le march\xe9 du travail. Identifier les formations qui correspondent \xe0 sa situation. Ce n'est pas un programme de sensibilisation g\xe9n\xe9rique. C'est une approche citoyenne, construite pour que chacun puisse garder la main sur son avenir.\n\n**Marius IA : le m\xeame projet, c\xf4t\xe9 organisations**\n\nL'ICIA n'intervient pas seul dans cet \xe9cosyst\xe8me. Marius IA, bas\xe9 au Campus Cyber.IA Euromed de Marseille, partage la m\xeame conviction fondatrice et l'applique du c\xf4t\xe9 des entreprises, des professions lib\xe9rales, des \xe9tablissements d'enseignement et des collectivit\xe9s.\n\nSa posture est celle de l'architecte : d\xe9finir le besoin r\xe9el, \xe9valuer l'impact, construire la solution avec les bons experts. Pas de solution pr\xe9con\xe7ue. Pas de lien avec des \xe9diteurs ou des int\xe9grateurs. Des recommandations qui ne servent que les int\xe9r\xeats du client, dans un secteur o\xf9 ce n'est pas la r\xe8gle.\n\nQuatre familles d'intervention structurent son offre : diagnostic IA et AI Act, formations sur mesure, accompagnement \xe0 la transformation, et une formule de suivi r\xe9gulier pour les organisations qui souhaitent un partenaire dans la dur\xe9e. Des livrables pr\xe9cis, des dur\xe9es annonc\xe9es, des r\xe9sultats mesurables.\n\n**Une m\xeame ligne**\n\nCe qui relie l'ICIA et Marius IA, ce n'est pas une structure juridique commune. C'est une vision partag\xe9e : permettre \xe0 chacun, qu'il soit citoyen ou d\xe9cideur, de prendre des d\xe9cisions \xe9clair\xe9es face \xe0 l'IA et de b\xe9n\xe9ficier de ses avanc\xe9es, avec une transformation lisible, ma\xeetris\xe9e et align\xe9e avec ses propres valeurs.\n\nD'un c\xf4t\xe9, des citoyens qui comprennent ce qui change dans leur quotidien. De l'autre, des organisations mieux \xe9quip\xe9es pour conduire leur transformation sans conflit d'int\xe9r\xeats. Les deux sont n\xe9cessaires. Les deux m\xe9ritent attention.\n\nL'ICIA est l'entr\xe9e pour ceux qui veulent comprendre. Marius IA est l'entr\xe9e pour ceux qui veulent agir. Les deux chemins m\xe8nent au m\xeame endroit.",bodyEn:"There is a very real paradox in the professional world today: everyone talks about artificial intelligence, but few people actually know what to do with it. Between the outsized promises of solution vendors and the growing regulatory complexity of the European AI Act, organizations and individuals alike often find themselves alone in front of decisions they do not feel equipped to make.\n\nThat paradox is exactly what ICIA chose to address.\n\n**ICIA: AI as a common good**\n\nThe Institut Collectif de l'Intelligence Artificielle is a public interest association. Its mission is simple to state, less simple to sustain: ensuring that artificial intelligence does not remain in the hands of a few.\n\nThe divide grows fast. Those who master the tools move forward. Those who do not understand them are left to absorb the consequences. And the public debate, often dominated by elitist or alarmist framing, offers them little help.\n\nICIA responds with practical, accessible workshops that require no technical background. Understanding what artificial intelligence actually is. Recognizing deepfakes and scams. Reading what is happening in the labor market. Identifying training that fits your situation. This is not a generic awareness program. It is a civic approach, built so that everyone can keep a hand on their own future.\n\n**Marius IA: the same project, on the organizational side**\n\nICIA does not operate alone in this ecosystem. Marius IA, based at the Campus Cyber.IA Euromed in Marseille, shares the same founding conviction and applies it on the side of companies, independent professionals, educational institutions, and public bodies.\n\nIts posture is that of the architect: define the real need, assess the impact, build the solution with the right experts. No pre-packaged answer. No ties to software vendors or integrators. Recommendations that serve only the client's interests, in a sector where that is far from standard practice.\n\nFour service lines structure its offer: AI and AI Act diagnostics, tailored training programs, transformation support, and an ongoing partnership format for organizations that want continuity. Defined deliverables, stated timeframes, measurable outcomes.\n\n**One line**\n\nWhat connects ICIA and Marius IA is not a shared legal structure. It is a shared vision: enabling everyone, whether citizen or decision-maker, to make informed choices about AI and to benefit from its advances, through a transformation that is legible, controlled, and aligned with their own values.\n\nOn one side, citizens who understand what is changing in their daily lives. On the other, organizations better equipped to lead their transformation without conflict of interest. Both matter. Both deserve attention.\n\nICIA is the entry point for those who want to understand. Marius IA is the entry point for those who want to act. Both paths lead to the same place.",category:"institutionnel",date:"2026-05-04",image:"/images/publications/icia-marius-ia-deux-projets-meme-conviction/hello.avif"},{slug:"icia-association-loi-1901",title:"L'Institut Collectif de l'IA est officiellement constitu\xe9 en association loi 1901",titleEn:"The Institut Collectif de l'IA officially established as a non-profit association",excerpt:"L'ICIA est d\xe9sormais une association loi 1901 d\xe9di\xe9e aux enjeux collectifs de l'intelligence artificielle. Une nouvelle \xe9tape pour la mission d'int\xe9r\xeat g\xe9n\xe9ral.",excerptEn:"ICIA is now a French non-profit association dedicated to the collective challenges of artificial intelligence. A new milestone for the public interest mission.",body:"L'Institut Collectif de l'IA (ICIA) vient d'\xeatre officiellement constitu\xe9 en association loi 1901, marquant une \xe9tape importante dans le d\xe9veloppement de sa mission d'int\xe9r\xeat g\xe9n\xe9ral.\n\n\n## Une mission claire\n\nL'ICIA poursuit une mission articul\xe9e autour de quatre axes :\n\n- Rendre l'IA intelligible\n- D\xe9velopper les comp\xe9tences\n- R\xe9duire les fractures num\xe9riques\n- Favoriser un d\xe9bat inform\xe9\n\n## Un ancrage marseillais\n\nBas\xe9e au Campus Cyber.IA Euromed \xe0 Marseille, l'association partage son implantation avec Mariusia, dans un environnement consacr\xe9 aux initiatives \xe9ducatives, cr\xe9atives et entrepreneuriales.",bodyEn:"The Institut Collectif de l'IA (ICIA) has just been officially established as a French non-profit association, marking an important milestone in the development of its public interest mission.\n\n\n## A clear mission\n\nICIA pursues a mission structured around four axes:\n\n- Making AI understandable\n- Developing skills\n- Reducing digital divides\n- Fostering informed debate\n\n## A Marseille anchor\n\nBased at Campus Cyber.IA Euromed in Marseille, the association shares its location with Mariusia, in an environment dedicated to educational, creative and entrepreneurial initiatives.",category:"institutionnel",date:"2026-04-28",image:"/images/publications/icia-association-loi-1901/icia-article.webp"}];function s(e){return t.slice(0,e)}},9181:function(e,n,i){i.d(n,{T7:function(){return s},XK:function(){return t}});let t=[],s=[]}}]);